// FIX: $() em vez de $node[]
const snapshots = $("MongoDB - Buscar snapshots").all().map(i => i.json);
const categoriasExistentes = $input.all().map(i => i.json.nome_original);

const nomesUnicos = new Set();

snapshots.forEach(snap => {
  (snap.auditoria_profissionais || []).forEach(prof => {
    // Serviços
    Object.keys(prof.servicos_valor || {}).forEach(n => nomesUnicos.add(n));
    // Produtos
    Object.keys(prof.produtos_valor || {}).forEach(n => nomesUnicos.add(n));
    // Pacotes/Assinaturas por profissional (se existir)
    Object.keys(prof.pacotes_valor || {}).forEach(n => nomesUnicos.add(n));
  });
  // Nomes de pacotes/assinaturas do campo pacotes.itens
  (snap.pacotes?.itens || []).forEach(p => {
    if (p.nome) nomesUnicos.add(p.nome);
  });
});

const nomesNovos = [...nomesUnicos].filter(n => !categoriasExistentes.includes(n));

return [{ json: { nomesNovos, snapshots } }];

// FIX: $() em vez de $node[]
const snapshots = $("Code - Extrair nomes novos").first().json.snapshots;

// Categorias salvas no MongoDB
const categorias = $("MongoDB - Buscar service_categories").all()
  .reduce((acc, i) => { acc[i.json.nome_original] = i.json.categoria; return acc; }, {});

// Mescla categorias novas retornadas pelo Gemini (branch true)
try {
  const chainFirst = $("LLM Chain - Normalizar").first();
  if (chainFirst) {
    const raw = chainFirst.json.text || "{}";
    Object.assign(categorias, JSON.parse(raw));
  }
} catch (e) {}

const metricas = snapshots.map(snap => {
  const fat      = snap.financeiro?.faturamento_total     || 0;
  const lucro    = snap.financeiro?.lucro_real            || 0;
  const servicos = snap.financeiro?.faturamento_servicos  || 0;
  const produtos = snap.financeiro?.faturamento_produtos  || 0;
  // Pacotes: tenta campo dedicado, fallback em pacotes.receita_total
  const pacotes  = snap.financeiro?.faturamento_pacotes
                || snap.pacotes?.receita_total
                || 0;

  const barbeiros = snap.ranking_barbeiros || [];
  const ticket = barbeiros.length
    ? barbeiros.reduce((a, b) => a + (b.ticket_medio || 0), 0) / barbeiros.length
    : 0;

  const retencao = (snap.clientes?.base_total || 0) > 0
    ? (snap.clientes.retorno_clientes || 0) / snap.clientes.base_total
    : 0;

  const tem_pacotes = (snap.pacotes?.quantidade_total_vendida || 0) > 0;

  // ── por_categoria: agora cobre serviços + produtos + pacotes ──
  const por_categoria = {};

  (snap.auditoria_profissionais || []).forEach(prof => {
    // Serviços
    Object.entries(prof.servicos_valor || {}).forEach(([nome, valor]) => {
      const cat = categorias[nome] || "outros";
      por_categoria[cat] = (por_categoria[cat] || 0) + valor;
    });
    // Produtos
    Object.entries(prof.produtos_valor || {}).forEach(([nome, valor]) => {
      const cat = categorias[nome] || "produto_consumivel";
      por_categoria[cat] = (por_categoria[cat] || 0) + valor;
    });
    // Pacotes/Assinaturas por profissional (se existir)
    Object.entries(prof.pacotes_valor || {}).forEach(([nome, valor]) => {
      const cat = categorias[nome] || "pacote_assinatura";
      por_categoria[cat] = (por_categoria[cat] || 0) + valor;
    });
  });

  // Fallback: se receita de pacotes existe mas não veio por profissional
  if (pacotes > 0 && !por_categoria["pacote_assinatura"]) {
    por_categoria["pacote_assinatura"] = pacotes;
  }

  return {
    slug:                 snap.meta?.unidade_slug,
    margem:               fat > 0 ? lucro / fat : 0,
    pct_servicos:         fat > 0 ? servicos / fat : 0,
    pct_produtos:         fat > 0 ? produtos / fat : 0,
    pct_pacotes:          fat > 0 ? pacotes  / fat : 0,
    faturamento_servicos: servicos,
    faturamento_produtos: produtos,
    faturamento_pacotes:  pacotes,
    ticket_medio:         ticket,
    retencao,
    tem_pacotes,
    por_categoria
  };
});

const LABELS = ["Barbearia A","Barbearia B","Barbearia C","Barbearia D",
               "Barbearia E","Barbearia F","Barbearia G","Barbearia H"];
const shuffled = [...LABELS].sort(() => Math.random() - 0.5);

const anonimizado = metricas.map((m, i) => ({ label: shuffled[i], ...m }));

const calcMedia = (campo) => {
  const validos = anonimizado.filter(c => c[campo] > 0);
  if (validos.length < 3) return null;
  return validos.reduce((a, c) => a + c[campo], 0) / validos.length;
};

const media = {
  margem:       calcMedia("margem"),
  ticket_medio: calcMedia("ticket_medio"),
  pct_servicos: calcMedia("pct_servicos"),
  pct_produtos: calcMedia("pct_produtos"),
  pct_pacotes:  calcMedia("pct_pacotes"),
  retencao:     calcMedia("retencao")
};

const comPacotes = anonimizado.filter(c => c.tem_pacotes).length;

return [{ json: { anonimizado, media, total: metricas.length, comPacotes } }];
